function extractResult(actions) {
  if (!actions) return { type: 'N/A', value: 0 };
  const RESULT_TYPES = [
    { key: 'onsite_conversion.total_messaging_connection', label: 'Mensagens' },
    { key: 'onsite_conversion.lead', label: 'Leads' },
