  ];
  for (const rt of RESULT_TYPES) {
    const act = actions.find(a => a.action_type === rt.key);
    if (act && parseInt(act.value) > 0) {
      return { type: rt.label, value: parseInt(act.value) };
    }
  }
  return { type: 'Engajamento', value: parseInt((actions.find(a=>a.action_type==='post_engagement')||{value:'0'}).value) };
}

function getCPA(costPerAction, actions) {
  if (!costPerAction) return null;
  const RESULT_TYPES = [
    'onsite_conversion.total_messaging_connection',
    'onsite_conversion.lead',
    'lead',
    'offsite_complete_registration_add_meta_leads',
    'onsite_web_lead',
    'link_click',
  ];
  for (const rt of RESULT_TYPES) {
    const c = costPerAction.find(a => a.action_type === rt);
    if (c) return parseFloat(c.value);
  }
  return null;
}

function generateRecommendations(account, campaigns) {
  const recs = [];
  const totalSpend = campaigns.reduce((s, c) => s + c.spend, 0);
  const avgCTR = campaigns.reduce((s, c) => s + c.ctr, 0) / (campaigns.length || 1);
  const avgCPC = campaigns.reduce((s, c) => s + (c.cpc || 0), 0) / (campaigns.length || 1);

  for (const camp of campaigns) {
    const campRecs = [];

    if (camp.ctr < 0.5) {
      campRecs.push({ type: 'warning', text: `CTR muito baixo (${camp.ctr.toFixed(2)}%) — Teste novos criativos com chamada para ação mais direta. Considere vídeos curtos com gancho nos primeiros 3 segundos.` });
    } else if (camp.ctr > 2.0) {
      campRecs.push({ type: 'success', text: `CTR excelente (${camp.ctr.toFixed(2)}%) — Considere aumentar o orçamento desta campanha para escalar os resultados.` });
    }

    if (camp.cpc > 2.0) {
      campRecs.push({ type: 'warning', text: `CPC alto (R$${camp.cpc.toFixed(2)}) — Refine a segmentação de público ou use Advantage+ para otimizar automaticamente.` });
    }

    if (camp.frequency > 2.5) {
      campRecs.push({ type: 'danger', text: `Frequência alta (${camp.frequency.toFixed(1)}x) — Público saturado! Expanda o público ou renove os criativos urgentemente.` });
    }

    if (camp.cpa && camp.cpa > 50) {
      campRecs.push({ type: 'warning', text: `CPA elevado (R$${camp.cpa.toFixed(2)}) — Revise a landing page / conversa de WhatsApp para melhorar conversão.` });
    } else if (camp.cpa && camp.cpa < 15) {
      campRecs.push({ type: 'success', text: `CPA ótimo (R$${camp.cpa.toFixed(2)}) — Aumente o investimento para escalar resultados.` });
    }

    if (camp.results > 0 && camp.cpa) {
      if (camp.objective && camp.objective.includes('TRAFEGO')) {
        campRecs.push({ type: 'info', text: `Campanha de tráfego com ${camp.results} cliques. Verifique se a página de destino está otimizada para conversão.` });
      }
    }

    if (campRecs.length === 0) {
      campRecs.push({ type: 'info', text: `Performance estável. Monitore diariamente e teste novos criativos a cada 14 dias para evitar fadiga de anúncio.` });
    }

    camp.recommendations = campRecs;
  }

  // Account-level recommendations
  if (totalSpend > 0) {
    if (campaigns.some(c => c.frequency > 2.0)) {
      recs.push({ type: 'danger', text: 'Algumas campanhas com frequência alta — renovação de criativos necessária.' });
    }
    if (campaigns.some(c => c.ctr > 1.5)) {
      recs.push({ type: 'success', text: 'Campanhas com bom CTR identificadas — considere escalar orçamento.' });
    }
    const lowCPA = campaigns.filter(c => c.cpa && c.cpa < 20);
    if (lowCPA.length > 0) {
      recs.push({ type: 'success', text: `${lowCPA.length} campanha(s) com CPA abaixo de R$20 — excelente performance, escale!` });
    }
  }

  return recs;
}

const allAccounts = [];

for (const [actId, actName] of Object.entries(ACCOUNT_NAMES)) {
  const insightFile = path.join(DATA_DIR, `${actId}_insights.json`);
  const campaignFile = path.join(DATA_DIR, `${actId}_campaigns.json`);

  let adsets = [];
  let campaigns = [];

  if (fs.existsSync(insightFile)) {
    const raw = JSON.parse(fs.readFileSync(insightFile, 'utf8'));
    adsets = raw.data || [];
  }

  if (fs.existsSync(campaignFile)) {
    const raw = JSON.parse(fs.readFileSync(campaignFile, 'utf8'));
    campaigns = raw.data || [];
  }

  if (adsets.length === 0 && campaigns.length === 0) {
    allAccounts.push({
      id: actId,
      name: actName,
      status: 'inactive',
      totalSpend: 0,
      totalImpressions: 0,
      totalClicks: 0,
      totalReach: 0,
      avgCTR: 0,
      avgCPC: 0,
      avgCPM: 0,
      avgFrequency: 0,
      totalResults: 0,
      resultType: 'N/A',
      avgCPA: null,
      campaigns: [],
      adsets: [],
      recommendations: [{ type: 'info', text: 'Nenhuma campanha ativa no período 01/04 - 17/04/2026.' }]
    });
    continue;
  }

  // Process adsets
  const processedAdsets = adsets.map(ad => {
    const result = extractResult(ad.actions);
    const cpa = getCPA(ad.cost_per_action_type, ad.actions);
    return {
      id: ad.adset_id,
      name: ad.adset_name,
      campaignId: ad.campaign_id,
      campaignName: ad.campaign_name,
      impressions: parseInt(ad.impressions || 0),
      clicks: parseInt(ad.clicks || 0),
      spend: parseFloat(ad.spend || 0),
      reach: parseInt(ad.reach || 0),
      ctr: parseFloat(ad.ctr || 0),
      cpc: parseFloat(ad.cpc || 0),
      cpm: parseFloat(ad.cpm || 0),
      cpp: parseFloat(ad.cpp || 0),
      frequency: parseFloat(ad.frequency || 0),
      uniqueClicks: parseInt(ad.unique_clicks || 0),
      uniqueCTR: parseFloat(ad.unique_ctr || 0),
      results: result.value,
      resultType: result.type,
      cpa: cpa
    };
  });

  // Process campaigns
  const processedCampaigns = campaigns.map(camp => {
    const result = extractResult(camp.actions);
    const cpa = getCPA(camp.cost_per_action_type, camp.actions);
    return {
      id: camp.campaign_id,
      name: camp.campaign_name,
      impressions: parseInt(camp.impressions || 0),
      clicks: parseInt(camp.clicks || 0),
      spend: parseFloat(camp.spend || 0),
      reach: parseInt(camp.reach || 0),
      ctr: parseFloat(camp.ctr || 0),
      cpc: parseFloat(camp.cpc || 0),
      cpm: parseFloat(camp.cpm || 0),
      cpp: parseFloat(camp.cpp || 0),
      frequency: parseFloat(camp.frequency || 0),
      uniqueClicks: parseInt(camp.unique_clicks || 0),
      uniqueCTR: parseFloat(camp.unique_ctr || 0),
      results: result.value,
      resultType: result.type,
      cpa: cpa,
      recommendations: []
    };
  });

  generateRecommendations(actName, processedCampaigns);

  const totalSpend = processedAdsets.reduce((s, a) => s + a.spend, 0);
  const totalImpressions = processedAdsets.reduce((s, a) => s + a.impressions, 0);
  const totalClicks = processedAdsets.reduce((s, a) => s + a.clicks, 0);
  const totalReach = processedAdsets.reduce((s, a) => s + a.reach, 0);
  const avgCTR = processedAdsets.length > 0 ? processedAdsets.reduce((s, a) => s + a.ctr, 0) / processedAdsets.length : 0;
  const avgCPC = processedAdsets.length > 0 ? processedAdsets.reduce((s, a) => s + a.cpc, 0) / processedAdsets.length : 0;
  const avgCPM = processedAdsets.length > 0 ? processedAdsets.reduce((s, a) => s + a.cpm, 0) / processedAdsets.length : 0;
  const avgFrequency = processedAdsets.length > 0 ? processedAdsets.reduce((s, a) => s + a.frequency, 0) / processedAdsets.length : 0;

  // Aggregate results
  const allResults = processedAdsets.reduce((s, a) => s + a.results, 0);
  const resultTypes = processedAdsets.map(a => a.resultType).filter(t => t !== 'N/A' && t !== 'Engajamento');
  const mainResultType = resultTypes[0] || processedAdsets[0]?.resultType || 'N/A';

  // CPA: total spend / total results
  const avgCPA = allResults > 0 ? totalSpend / allResults : null;

  const accountRecs = generateRecommendations(actName, processedCampaigns);

  allAccounts.push({
    id: actId,
    name: actName,
    status: 'active',
    totalSpend,
    totalImpressions,
    totalClicks,
    totalReach,
    avgCTR,
    avgCPC,
    avgCPM,
    avgFrequency,
    totalResults: allResults,
    resultType: mainResultType,
    avgCPA,
    campaigns: processedCampaigns,
    adsets: processedAdsets,
    recommendations: accountRecs
  });
}

// Save raw combined data
fs.writeFileSync(
  path.join(DATA_DIR, 'combined_raw.json'),
  JSON.stringify(allAccounts, null, 2),
  'utf8'
);

// Summary
const active = allAccounts.filter(a => a.status === 'active');
console.log('Total accounts:', allAccounts.length);
console.log('Active:', active.length);
console.log('Total spend: R$', active.reduce((s, a) => s + a.totalSpend, 0).toFixed(2));
console.log('Total impressions:', active.reduce((s, a) => s + a.totalImpressions, 0));
active.forEach(a => {
  console.log(`  ${a.name}: R$${a.totalSpend.toFixed(2)} spend | ${a.adsets.length} adsets | ${a.totalResults} resultados (${a.resultType}) | CPA: ${a.avgCPA ? 'R$'+a.avgCPA.toFixed(2) : 'N/A'}`);
});

console.log('\nDone! combined_raw.json saved.');
