const fs = require('fs');
const path = require('path');

const DATA_DIR = 'C:/Users/trafe/.claude/meta-dashboard/data';

const ACCOUNT_NAMES = {
  'act_267770730525130': 'Helena Coelho',
  'act_2410626089217011': '2410626089217011',
  'act_1182499605271369': 'MM Protege',
