@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body {
    @apply bg-gray-950 text-gray-100 font-sans;
  }
  * {
    @apply box-border;
  }
}

@layer components {
  .card {
    @apply bg-gray-900 border border-gray-800 rounded-xl p-5;
  }
  .badge-active {
    @apply bg-green-900/40 text-green-400 border border-green-800 text-xs px-2 py-0.5 rounded-full;
  }
  .badge-paused {
    @apply bg-yellow-900/40 text-yellow-400 border border-yellow-800 text-xs px-2 py-0.5 rounded-full;
  }
  .badge-deleted {
    @apply bg-red-900/40 text-red-400 border border-red-800 text-xs px-2 py-0.5 rounded-full;
  }
  .btn-primary {
    @apply bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors;
  }
  .input-field {
    @apply bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-gray-100 placeholder-gray-500 focus:outline-none focus:border-blue-500 w-full;
  }
}

::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: #111827;
}
::-webkit-scrollbar-thumb {
  background: #374151;
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: #4B5563;
}

